#include<bits/stdc++.h>
using namespace std;
long long n,a[100010],ans[100010],s[100010],d[100010];
vector<pair<long long,long long>> mp[100010];
void dfs(long long x,long long fa=-1)
{
    ans[1]+=d[x]*a[x];
    s[x]=a[x];
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=fa)
        {
            d[v]=d[x]+val;
            dfs(v,x);
            s[x]+=s[v];
        }
    }
}
void dp(long long x,long long fa=-1)
{
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=fa)
        {
            ans[v]=ans[x]-s[v]*val+(s[1]-s[v])*val;
            dp(v,x);
        }
    }
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    for(long long i=1;i<n;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    dfs(1);
    dp(1);
    long long res=LLONG_MAX;
    for(long long i=1;i<=n;i++)
    {
        res=min(res,ans[i]);
    }
    printf("%lld",res);
    return 0;
}
